    childId,
    date,
    status,
    clockTime,
    notes,
    pickupTime,
    pickedUpBy,
    createdAt,
    updatedAt,
  );
  @override
  bool operator ==(Object other) =>
      identical(this, other) ||
      (other is AttendanceData &&
          other.childId == this.childId &&
          other.date == this.date &&
